arguments.prompt:
You are implementing a Blazor Web App for a veterinary clinic. The project is already scaffolded at `/tmp/sv-d728891e2ace4d79bba46d81aab2c0c8/VetClinic` with:
- .NET 11 preview, Interactive Server global mode, ASP.NET Core Identity with SQLite
- The template has Counter.razor, Weather.razor, Auth.razor demo pages that need to be REMOVED
- `Data/ApplicationDbContext.cs` and `Data/ApplicationUser.cs` exist

## Requirements
- Patient records: register pets, view/edit medical history, add treatment notes
- Appointment scheduling: create, reschedule, cancel — calendar shows real-time availability
- Billing: generate invoices, process payments, view payment history
- All pages require authentication (staff login)
- Every page involves data entry and real-time UI interactions

## What to implement

### 1. Data Models (create in `Data/` folder)

Create `Data/Models.cs` with these entities:

```csharp
namespace VetClinic.Data;

public class Owner
{
    public int Id { get; set; }
    public string FirstName { get; set; } = "";
    public string LastName { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Email { get; set; } = "";
    public List<Pet> Pets { get; set; } = new();
}

public class Pet
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Species { get; set; } = ""; // Dog, Cat, Bird, etc.
    public string Breed { get; set; } = "";
    public DateTime DateOfBirth { get; set; }
    public decimal Weight { get; set; }
    public int OwnerId { get; set; }
    public Owner Owner { get; set; } = null!;
    public List<TreatmentNote> TreatmentNotes { get; set; } = new();
    public List<Appointment> Appointments { get; set; } = new();
}

public class TreatmentNote
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime Date { get; set; }
    public string Diagnosis { get; set; } = "";
    public string Treatment { get; set; } = "";
    public string Medications { get; set; } = "";
    public string Notes { get; set; } = "";
    public string VeterinarianName { get; set; } = "";
}

public class Appointment
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime StartTime { get; set; }
    public DateTime EndTime { get; set; }
    public string Reason { get; set; } = "";
    public AppointmentStatus Status { get; set; }
    public string VeterinarianName { get; set; } = "";
    public string Notes { get; set; } = "";
}

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled
}

public class Invoice
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public int? AppointmentId { get; set; }
    public Appointment? Appointment { get; set; }
    public DateTime IssuedDate { get; set; }
    public DateTime? DueDate { get; set; }
    public List<InvoiceLineItem> LineItems { get; set; } = new();
    public decimal TotalAmount => LineItems.Sum(li => li.Amount);
    public decimal AmountPaid => Payments.Sum(p => p.Amount);
    public decimal BalanceDue => TotalAmount - AmountPaid;
    public InvoiceStatus Status { get; set; }
    public List<Payment> Payments { get; set; } = new();
}

public class InvoiceLineItem
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public string Description { get; set; } = "";
    public decimal Amount { get; set; }
}

public enum InvoiceStatus
{
    Draft,
    Issued,
    Paid,
    Overdue
}

public class Payment
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public DateTime PaymentDate { get; set; }
    public decimal Amount { get; set; }
    public PaymentMethod Method { get; set; }
    public string Reference { get; set; } = "";
}

public enum PaymentMethod
{
    Cash,
    CreditCard,
    DebitCard,
    Check,
    BankTransfer
}
```

### 2. Update ApplicationDbContext

Edit `Data/ApplicationDbContext.cs` to add DbSets and configure relationships:

```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<TreatmentNote> TreatmentNotes => Set<TreatmentNote>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceLineItem> InvoiceLineItems => Set<InvoiceLineItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Pet>()
            .HasOne(p => p.Owner)
            .WithMany(o => o.Pets)
            .HasForeignKey(p => p.OwnerId);

        builder.Entity<TreatmentNote>()
            .HasOne(t => t.Pet)
            .WithMany(p => p.TreatmentNotes)
            .HasForeignKey(t => t.PetId);

        builder.Entity<Appointment>()
            .HasOne(a => a.Pet)
            .WithMany(p => p.Appointments)
            .HasForeignKey(a => a.PetId);

        builder.Entity<Invoice>()
            .HasOne(i => i.Pet)
            .WithMany()
            .HasForeignKey(i => i.PetId);

        builder.Entity<Invoice>()
            .HasOne(i => i.Appointment)
            .WithMany()
            .HasForeignKey(i => i.AppointmentId);

        builder.Entity<InvoiceLineItem>()
            .HasOne(li => li.Invoice)
            .WithMany(i => i.LineItems)
            .HasForeignKey(li => li.InvoiceId);

        builder.Entity<Payment>()
            .HasOne(p => p.Invoice)
            .WithMany(i => i.Payments)
            .HasForeignKey(p => p.InvoiceId);

        builder.Entity<Invoice>()
            .Property(i => i.TotalAmount)
            .HasComputedColumnSql(null);

        builder.Entity<Invoice>()
            .Ignore(i => i.TotalAmount)
            .Ignore(i => i.AmountPaid)
            .Ignore(i => i.BalanceDue);
    }
}
```

Wait - the computed properties TotalAmount, AmountPaid, BalanceDue should just be ignored by EF since they're computed in-memory. Let me fix:

```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<TreatmentNote> TreatmentNotes => Set<TreatmentNote>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceLineItem> InvoiceLineItems => Set<InvoiceLineItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Pet>()
            .HasOne(p => p.Owner)
            .WithMany(o => o.Pets)
            .HasForeignKey(p => p.OwnerId);

        builder.Entity<TreatmentNote>()
            .HasOne(t => t.Pet)
            .WithMany(p => p.TreatmentNotes)
            .HasForeignKey(t => t.PetId);

        builder.Entity<Appointment>()
            .HasOne(a => a.Pet)
            .WithMany(p => p.Appointments)
            .HasForeignKey(a => a.PetId);

        builder.Entity<Invoice>()
            .HasOne(i => i.Pet)
            .WithMany()
            .HasForeignKey(i => i.PetId);

        builder.Entity<Invoice>()
            .HasOne(i => i.Appointment)
            .WithMany()
            .HasForeignKey(i => i.AppointmentId);

        builder.Entity<Invoice>()
            .Ignore(i => i.TotalAmount)
            .Ignore(i => i.AmountPaid)
            .Ignore(i => i.BalanceDue);

        builder.Entity<InvoiceLineItem>()
            .HasOne(li => li.Invoice)
            .WithMany(i => i.LineItems)
            .HasForeignKey(li => li.InvoiceId);

        builder.Entity<Payment>()
            .HasOne(p => p.Invoice)
            .WithMany(i => i.Payments)
            .HasForeignKey(p => p.InvoiceId);
    }
}
```

