            @foreach (var apt in upcomingAppointments)
            {
                <tr>
                    <td>@apt.StartTime.ToString("g")</td>
                    <td>@apt.Pet.Name (@apt.Pet.Species)</td>
                    <td>@apt.Pet.Owner.FirstName @apt.Pet.Owner.LastName</td>
