                    <td>@apt.VeterinarianName</td>
                </tr>
            }
        </tbody>
    </table>
}
else
{
    <p class="text-muted">No upcoming appointments.</p>
}

@code {
    private int petCount;
    private int todayAppointments;
    private int pendingInvoices;
    private int ownerCount;
    private List<Appointment> upcomingAppointments = new();

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.Today;
        petCount = await Db.Pets.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        todayAppointments = await Db.Appointments
            .Where(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled)
            .CountAsync();
        pendingInvoices = await Db.Invoices
            .Where(i => i.Status == InvoiceStatus.Issued || i.Status == InvoiceStatus.Overdue)
            .CountAsync();
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime >= DateTime.Now && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(10)
            .ToListAsync();
    }
}
