@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Patients</PageTitle>

<h1>Patient Management</h1>

<div class="row mb-3">
    <div class="col">
        <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowRegisterOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowRegisterPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "Register New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save Owner</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelOwnerForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.Species">
                            <option value="">Select...</option>
                            <option value="Dog">Dog</option>
                            <option value="Cat">Cat</option>
                            <option value="Bird">Bird</option>
                            <option value="Rabbit">Rabbit</option>
                            <option value="Reptile">Reptile</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.Weight" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.OwnerId">
                            <option value="0">Select owner...</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <button type="submit" class="btn btn-success mt-2">Save Pet</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelPetForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet</th><th>Species</th><th>Breed</th><th>Age</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in filteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@GetAge(pet.DateOfBirth)</td>
                <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    <a href="@($"patients/{pet.Id}")" class="btn btn-sm btn-outline-info">Medical History</a>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Pet> pets = new();
    private List<Pet> filteredPets = new();
    private List<Owner> owners = new();
    private string searchTerm = "";
    private bool showOwnerForm;
    private bool showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        Search();
    }

    private void Search()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            filteredPets = pets;
        }
        else
        {
            var term = searchTerm.ToLower();
            filteredPets = pets.Where(p =>
                p.Name.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.FirstName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.LastName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Species.Contains(term, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private void ShowRegisterOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
        showPetForm = false;
    }

    private void ShowRegisterPet()
    {
        editingPet = new Pet { DateOfBirth = DateTime.Today };
        showPetForm = true;
        showOwnerForm = false;
    }

    private void CancelOwnerForm() => showOwnerForm = false;
    private void CancelPetForm() => showPetForm = false;

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            Db.Owners.Add(editingOwner);
        else
            Db.Owners.Update(editingOwner);
        await Db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (editingPet.Id == 0)
            Db.Pets.Add(editingPet);
        else
            Db.Pets.Update(editingPet);
        await Db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showPetForm = true;
        showOwnerForm = false;
    }

    private string GetAge(DateTime dob)
    {
        var age = DateTime.Today.Year - dob.Year;
        if (dob.Date > DateTime.Today.AddYears(-age)) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

@page "/patients/{PetId:int}"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patient - @pet?.Name</PageTitle>

@if (pet is null)
{
    <p>Loading...</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="patients">Patients</a></li>
            <li class="breadcrumb-item active">@pet.Name</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header d-flex justify-content-between">
                    <span>Patient Info</span>
                    <button class="btn btn-sm btn-outline-primary" @onclick="ToggleEditPet">@(editingPetInfo ? "Cancel" : "Edit")</button>
                </div>
                <div class="card-body">
                    @if (editingPetInfo)
                    {
                        <EditForm Model="pet" OnValidSubmit="SavePetInfo" FormName="editPetInfo">
                            <div class="mb-2">
                                <label class="form-label">Name</label>
                                <InputText class="form-control" @bind-Value="pet.Name" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Species</label>
                                <InputText class="form-control" @bind-Value="pet.Species" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Breed</label>
                                <InputText class="form-control" @bind-Value="pet.Breed" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Weight (kg)</label>
                                <InputNumber class="form-control" @bind-Value="pet.Weight" />
                            </div>
                            <button type="submit" class="btn btn-primary">Save</button>
                        </EditForm>
                    }
                    else
                    {
                        <p><strong>Species:</strong> @pet.Species</p>
                        <p><strong>Breed:</strong> @pet.Breed</p>
                        <p><strong>DOB:</strong> @pet.DateOfBirth.ToShortDateString()</p>
                        <p><strong>Weight:</strong> @pet.Weight kg</p>
                        <p><strong>Owner:</strong> @pet.Owner.FirstName @pet.Owner.LastName</p>
                        <p><strong>Phone:</strong> @pet.Owner.Phone</p>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-8">
            <div class="d-flex justify-content-between align-items-center mb-3">
                <h3>Medical History</h3>
                <button class="btn btn-success" @onclick="ShowAddNote">+ Add Treatment Note</button>
            </div>

            @if (showNoteForm)
            {
                <div class="card mb-3 border-success">
                    <div class="card-body">
                        <EditForm Model="editingNote" OnValidSubmit="SaveNote" FormName="noteForm">
                            <div class="row">
                                <div class="col-md-6">
                                    <label class="form-label">Date</label>
                                    <InputDate class="form-control" @bind-Value="editingNote.Date" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Veterinarian</label>
                                    <InputText class="form-control" @bind-Value="editingNote.VeterinarianName" />
                                </div>
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Diagnosis</label>
                                <InputText class="form-control" @bind-Value="editingNote.Diagnosis" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Treatment</label>
                                <InputTextArea class="form-control" @bind-Value="editingNote.Treatment" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Medications</label>
                                <InputText class="form-control" @bind-Value="editingNote.Medications" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Notes</label>
                                <InputTextArea class="form-control" @bind-Value="editingNote.Notes" />
                            </div>
                            <button type="submit" class="btn btn-success">Save Note</button>
                            <button type="button" class="btn btn-secondary" @onclick="() => showNoteForm = false">Cancel</button>
                        </EditForm>
                    </div>
                </div>
            }

            @if (notes.Any())
            {
                @foreach (var note in notes)
                {
                    <div class="card mb-2">
                        <div class="card-header d-flex justify-content-between">
                            <span><strong>@note.Date.ToShortDateString()</strong> — @note.Diagnosis</span>
                            <span class="text-muted">Dr. @note.VeterinarianName</span>
                        </div>
                        <div class="card-body">
                            <p><strong>Treatment:</strong> @note.Treatment</p>
                            @if (!string.IsNullOrEmpty(note.Medications))
                            {
                                <p><strong>Medications:</strong> @note.Medications</p>
                            }
                            @if (!string.IsNullOrEmpty(note.Notes))
                            {
                                <p><strong>Notes:</strong> @note.Notes</p>
                            }
                        </div>
                    </div>
                }
            }
            else
            {
                <p class="text-muted">No medical history recorded yet.</p>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private List<TreatmentNote> notes = new();
    private bool editingPetInfo;
    private bool showNoteForm;
    private TreatmentNote editingNote = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pet = await Db.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == PetId);
        notes = await Db.TreatmentNotes
            .Where(n => n.PetId == PetId)
            .OrderByDescending(n => n.Date)
            .ToListAsync();
    }

    private void ToggleEditPet() => editingPetInfo = !editingPetInfo;

    private async Task SavePetInfo()
    {
        await Db.SaveChangesAsync();
        editingPetInfo = false;
    }

    private void ShowAddNote()
    {
        editingNote = new TreatmentNote { PetId = PetId, Date = DateTime.Today };
        showNoteForm = true;
    }

    private async Task SaveNote()
    {
        Db.TreatmentNotes.Add(editingNote);
        await Db.SaveChangesAsync();
        showNoteForm = false;
        await LoadData();
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointmentForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3 border-primary">
        <div class="card-header">@(editingAppointment.Id == 0 ? "Schedule New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment.PetId">
                            <option value="0">Select pet...</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FirstName @pet.Owner.LastName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" @bind-Value="appointmentDate" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Start Time</label>
                        <InputSelect class="form-select" @bind-Value="startTimeSlot">
                            @foreach (var slot in timeSlots)
                            {
                                <option value="@slot">@slot</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Duration (min)</label>
                        <InputSelect class="form-select" @bind-Value="durationMinutes">
                            <option value="15">15</option>
                            <option value="30">30</option>
                            <option value="45">45</option>
                            <option value="60">60</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.VeterinarianName" />
                    </div>
                </div>
                <div class="row mt-2">
                    <div class="col-md-6">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Notes" />
                    </div>
                </div>
                @if (!string.IsNullOrEmpty(formError))
                {
                    <div class="alert alert-danger mt-2">@formError</div>
                }
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<h4>Schedule for @selectedDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead>
                <tr><th style="width:100px">Time</th><th>Appointment</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var slot in timeSlots)
                {
                    var aptsInSlot = dayAppointments.Where(a => a.StartTime.ToString("HH:mm") == slot).ToList();
                    <tr class="@(aptsInSlot.Any() ? "table-info" : "")">
                        <td>@slot</td>
                        <td>
                            @if (aptsInSlot.Any())
                            {
                                @foreach (var apt in aptsInSlot)
                                {
                                    <span>@apt.Pet.Name — @apt.Reason (Dr. @apt.VeterinarianName)</span>
                                }
                            }
                            else
                            {
                                <span class="text-muted">Available</span>
                            }
                        </td>
                        <td>
                            @foreach (var apt in aptsInSlot)
                            {
                                <span class="badge @GetStatusBadge(apt.Status)">@apt.Status</span>
                            }
                        </td>
                        <td>
                            @foreach (var apt in aptsInSlot)
                            {
                                @if (apt.Status == AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-warning" @onclick="() => Reschedule(apt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                                }
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Availability Summary</div>
            <div class="card-body">
                <p><strong>Total slots:</strong> @timeSlots.Count</p>
                <p><strong>Booked:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled)</p>
                <p><strong>Available:</strong> @(timeSlots.Count - dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled))</p>
                <p><strong>Completed:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Completed)</p>
                <p><strong>Cancelled:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Cancelled)</p>
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private DateTime appointmentDate = DateTime.Today;
    private string startTimeSlot = "09:00";
    private int durationMinutes = 30;
    private List<Appointment> dayAppointments = new();
    private List<Pet> pets = new();
    private bool showForm;
    private Appointment editingAppointment = new();
    private string formError = "";

    private List<string> timeSlots = Enumerable.Range(8, 11)
        .SelectMany(h => new[] { $"{h:D2}:00", $"{h:D2}:30" })
        .ToList();

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        dayAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == selectedDate.Date)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    private void ShowNewAppointmentForm()
    {
        editingAppointment = new Appointment();
        appointmentDate = selectedDate;
        startTimeSlot = "09:00";
        durationMinutes = 30;
        formError = "";
        showForm = true;
    }

    private void CancelForm() => showForm = false;

    private async Task SaveAppointment()
    {
        formError = "";
        if (editingAppointment.PetId == 0)
        {
            formError = "Please select a pet.";
            return;
        }

        var timeParts = startTimeSlot.Split(':');
        var start = appointmentDate.Date.AddHours(int.Parse(timeParts[0])).AddMinutes(int.Parse(timeParts[1]));
        var end = start.AddMinutes(durationMinutes);

        var conflict = await Db.Appointments.AnyAsync(a =>
            a.Id != editingAppointment.Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.StartTime < end && a.EndTime > start);

        if (conflict)
        {
            formError = "This time slot conflicts with an existing appointment.";
            return;
        }

        editingAppointment.StartTime = start;
        editingAppointment.EndTime = end;
        editingAppointment.Status = AppointmentStatus.Scheduled;

        if (editingAppointment.Id == 0)
            Db.Appointments.Add(editingAppointment);
        else
            Db.Appointments.Update(editingAppointment);

        await Db.SaveChangesAsync();
        showForm = false;
        await LoadAppointments();
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        appointmentDate = apt.StartTime.Date;
        startTimeSlot = apt.StartTime.ToString("HH:mm");
        durationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        formError = "";
        showForm = true;
    }

    private async Task Complete(Appointment apt)
    {
        apt.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task Cancel(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/billing"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Billing</PageTitle>

<h1>Billing & Payments</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-3 border-primary">
            <div class="card-header">Create Invoice</div>
            <div class="card-body">
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Pet</label>
                        <select class="form-select" @bind="newInvoicePetId">
                            <option value="0">Select pet...</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FirstName @pet.Owner.LastName)</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Due Date</label>
                        <input type="date" class="form-control" @bind="newInvoiceDueDate" />
                    </div>
                </div>

                <h6>Line Items</h6>
                @for (int i = 0; i < lineItems.Count; i++)
                {
                    var idx = i;
                    <div class="row mb-1">
                        <div class="col-md-8">
                            <input type="text" class="form-control" placeholder="Description" @bind="lineItems[idx].Description" />
                        </div>
                        <div class="col-md-3">
                            <input type="number" class="form-control" placeholder="Amount" step="0.01" @bind="lineItems[idx].Amount" />
                        </div>
                        <div class="col-md-1">
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => lineItems.RemoveAt(idx)">×</button>
                        </div>
                    </div>
                }
                <button type="button" class="btn btn-sm btn-outline-secondary" @onclick="AddLineItem">+ Add Line</button>
                <div class="mt-2">
                    <strong>Total: $@lineItems.Sum(l => l.Amount).ToString("F2")</strong>
                </div>
                <div class="mt-2">
                    <button class="btn btn-primary" @onclick="SaveInvoice">Create Invoice</button>
                    <button class="btn btn-secondary" @onclick="() => showInvoiceForm = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    <table class="table table-striped">
        <thead>
            <tr><th>#</th><th>Date</th><th>Pet</th><th>Owner</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var inv in invoices)
            {
                <tr>
                    <td>@inv.Id</td>
                    <td>@inv.IssuedDate.ToShortDateString()</td>
                    <td>@inv.Pet.Name</td>
                    <td>@inv.Pet.Owner.FirstName @inv.Pet.Owner.LastName</td>
                    <td>$@inv.TotalAmount.ToString("F2")</td>
                    <td>$@inv.AmountPaid.ToString("F2")</td>
                    <td>$@inv.BalanceDue.ToString("F2")</td>
                    <td><span class="badge @GetInvoiceStatusBadge(inv.Status)">@inv.Status</span></td>
                    <td>
                        @if (inv.Status != InvoiceStatus.Paid)
                        {
                            <button class="btn btn-sm btn-outline-success" @onclick="() => ShowPaymentForm(inv)">Record Payment</button>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@if (activeTab == "payments")
{
    <table class="table table-striped">
        <thead>
            <tr><th>Date</th><th>Invoice #</th><th>Pet</th><th>Amount</th><th>Method</th><th>Reference</th></tr>
        </thead>
        <tbody>
            @foreach (var payment in payments)
            {
                <tr>
                    <td>@payment.PaymentDate.ToShortDateString()</td>
                    <td>@payment.InvoiceId</td>
                    <td>@payment.Invoice.Pet.Name</td>
                    <td>$@payment.Amount.ToString("F2")</td>
                    <td>@payment.Method</td>
                    <td>@payment.Reference</td>
                </tr>
            }
        </tbody>
    </table>
}

@if (showPaymentForm)
{
    <div class="modal d-block" tabindex="-1" style="background-color: rgba(0,0,0,0.5)">
        <div class="modal-dialog">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Record Payment — Invoice #@paymentInvoice!.Id</h5>
                    <button type="button" class="btn-close" @onclick="() => showPaymentForm = false"></button>
                </div>
                <div class="modal-body">
                    <p>Balance due: <strong>$@paymentInvoice!.BalanceDue.ToString("F2")</strong></p>
                    <div class="mb-2">
                        <label class="form-label">Amount</label>
                        <input type="number" class="form-control" step="0.01" @bind="newPayment.Amount" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Method</label>
                        <select class="form-select" @bind="newPayment.Method">
                            @foreach (var method in Enum.GetValues<PaymentMethod>())
                            {
                                <option value="@method">@method</option>
                            }
                        </select>
                    </div>
                    <div class="mb-2">
                        <label class="form-label">Reference</label>
                        <input type="text" class="form-control" @bind="newPayment.Reference" />
                    </div>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="() => showPaymentForm = false">Cancel</button>
                    <button class="btn btn-success" @onclick="ProcessPayment">Process Payment</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string activeTab = "invoices";
    private List<Invoice> invoices = new();
    private List<Payment> payments = new();
    private List<Pet> pets = new();
    private bool showInvoiceForm;
    private bool showPaymentForm;
    private int newInvoicePetId;
    private DateTime newInvoiceDueDate = DateTime.Today.AddDays(30);
    private List<InvoiceLineItem> lineItems = new();
    private Invoice? paymentInvoice;
    private Payment newPayment = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        invoices = await Db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments)
            .OrderByDescending(i => i.IssuedDate)
            .ToListAsync();
        payments = await Db.Payments
            .Include(p => p.Invoice).ThenInclude(i => i.Pet)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
    }

    private void ShowNewInvoice()
    {
        showInvoiceForm = true;
        newInvoicePetId = 0;
        newInvoiceDueDate = DateTime.Today.AddDays(30);
        lineItems = new() { new InvoiceLineItem() };
    }

    private void AddLineItem() => lineItems.Add(new InvoiceLineItem());

    private async Task SaveInvoice()
    {
        if (newInvoicePetId == 0) return;

        var invoice = new Invoice
        {
            PetId = newInvoicePetId,
            IssuedDate = DateTime.Today,
            DueDate = newInvoiceDueDate,
            Status = InvoiceStatus.Issued,
            LineItems = lineItems.Where(l => !string.IsNullOrWhiteSpace(l.Description)).ToList()
        };

        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        showInvoiceForm = false;
        await LoadData();
    }

    private void ShowPaymentForm(Invoice invoice)
    {
        paymentInvoice = invoice;
        newPayment = new Payment
        {
            InvoiceId = invoice.Id,
            PaymentDate = DateTime.Today,
            Amount = invoice.BalanceDue
        };
        showPaymentForm = true;
    }

    private async Task ProcessPayment()
    {
        Db.Payments.Add(newPayment);

        var invoice = await Db.Invoices
            .Include(i => i.Payments)
            .Include(i => i.LineItems)
            .FirstAsync(i => i.Id == newPayment.InvoiceId);

        var totalPaid = invoice.Payments.Sum(p => p.Amount) + newPayment.Amount;
        var total = invoice.LineItems.Sum(li => li.Amount);
        if (totalPaid >= total)
            invoice.Status = InvoiceStatus.Paid;

        await Db.SaveChangesAsync();
        showPaymentForm = false;
        await LoadData();
    }

    private string GetInvoiceStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Draft => "bg-secondary",
        InvoiceStatus.Issued => "bg-primary",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Patients</PageTitle>

<h1>Patient Management</h1>

<div class="row mb-3">
    <div class="col">
        <input type="text" class="form-control" placeholder="Search pets or owners..." @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-auto">
        <button class="btn btn-primary" @onclick="ShowRegisterOwner">+ New Owner</button>
        <button class="btn btn-success" @onclick="ShowRegisterPet">+ New Pet</button>
    </div>
</div>

@if (showOwnerForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingOwner.Id == 0 ? "Register New Owner" : "Edit Owner")</div>
        <div class="card-body">
            <EditForm Model="editingOwner" OnValidSubmit="SaveOwner" FormName="ownerForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">First Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.FirstName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Last Name</label>
                        <InputText class="form-control" @bind-Value="editingOwner.LastName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Phone</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Phone" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Email</label>
                        <InputText class="form-control" @bind-Value="editingOwner.Email" />
                    </div>
                </div>
                <button type="submit" class="btn btn-primary mt-2">Save Owner</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelOwnerForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (showPetForm)
{
    <div class="card mb-3">
        <div class="card-header">@(editingPet.Id == 0 ? "Register New Pet" : "Edit Pet")</div>
        <div class="card-body">
            <EditForm Model="editingPet" OnValidSubmit="SavePet" FormName="petForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-2">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="editingPet.Name" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Species</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.Species">
                            <option value="">Select...</option>
                            <option value="Dog">Dog</option>
                            <option value="Cat">Cat</option>
                            <option value="Bird">Bird</option>
                            <option value="Rabbit">Rabbit</option>
                            <option value="Reptile">Reptile</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="editingPet.Breed" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="editingPet.DateOfBirth" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="editingPet.Weight" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Owner</label>
                        <InputSelect class="form-select" @bind-Value="editingPet.OwnerId">
                            <option value="0">Select owner...</option>
                            @foreach (var owner in owners)
                            {
                                <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                            }
                        </InputSelect>
                    </div>
                </div>
                <button type="submit" class="btn btn-success mt-2">Save Pet</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelPetForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<table class="table table-hover">
    <thead>
        <tr><th>Pet</th><th>Species</th><th>Breed</th><th>Age</th><th>Owner</th><th>Actions</th></tr>
    </thead>
    <tbody>
        @foreach (var pet in filteredPets)
        {
            <tr>
                <td>@pet.Name</td>
                <td>@pet.Species</td>
                <td>@pet.Breed</td>
                <td>@GetAge(pet.DateOfBirth)</td>
                <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" @onclick="() => EditPet(pet)">Edit</button>
                    <a href="@($"patients/{pet.Id}")" class="btn btn-sm btn-outline-info">Medical History</a>
                </td>
            </tr>
        }
    </tbody>
</table>

@code {
    private List<Pet> pets = new();
    private List<Pet> filteredPets = new();
    private List<Owner> owners = new();
    private string searchTerm = "";
    private bool showOwnerForm;
    private bool showPetForm;
    private Owner editingOwner = new();
    private Pet editingPet = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
        Search();
    }

    private void Search()
    {
        if (string.IsNullOrWhiteSpace(searchTerm))
        {
            filteredPets = pets;
        }
        else
        {
            var term = searchTerm.ToLower();
            filteredPets = pets.Where(p =>
                p.Name.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.FirstName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Owner.LastName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                p.Species.Contains(term, StringComparison.OrdinalIgnoreCase)
            ).ToList();
        }
    }

    private void ShowRegisterOwner()
    {
        editingOwner = new Owner();
        showOwnerForm = true;
        showPetForm = false;
    }

    private void ShowRegisterPet()
    {
        editingPet = new Pet { DateOfBirth = DateTime.Today };
        showPetForm = true;
        showOwnerForm = false;
    }

    private void CancelOwnerForm() => showOwnerForm = false;
    private void CancelPetForm() => showPetForm = false;

    private async Task SaveOwner()
    {
        if (editingOwner.Id == 0)
            Db.Owners.Add(editingOwner);
        else
            Db.Owners.Update(editingOwner);
        await Db.SaveChangesAsync();
        showOwnerForm = false;
        await LoadData();
    }

    private async Task SavePet()
    {
        if (editingPet.Id == 0)
            Db.Pets.Add(editingPet);
        else
            Db.Pets.Update(editingPet);
        await Db.SaveChangesAsync();
        showPetForm = false;
        await LoadData();
    }

    private void EditPet(Pet pet)
    {
        editingPet = pet;
        showPetForm = true;
        showOwnerForm = false;
    }

    private string GetAge(DateTime dob)
    {
        var age = DateTime.Today.Year - dob.Year;
        if (dob.Date > DateTime.Today.AddYears(-age)) age--;
        return age < 1 ? "< 1 yr" : $"{age} yr";
    }
}

@page "/patients/{PetId:int}"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patient - @pet?.Name</PageTitle>

@if (pet is null)
{
    <p>Loading...</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="patients">Patients</a></li>
            <li class="breadcrumb-item active">@pet.Name</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header d-flex justify-content-between">
                    <span>Patient Info</span>
                    <button class="btn btn-sm btn-outline-primary" @onclick="ToggleEditPet">@(editingPetInfo ? "Cancel" : "Edit")</button>
                </div>
                <div class="card-body">
                    @if (editingPetInfo)
                    {
                        <EditForm Model="pet" OnValidSubmit="SavePetInfo" FormName="editPetInfo">
                            <div class="mb-2">
                                <label class="form-label">Name</label>
                                <InputText class="form-control" @bind-Value="pet.Name" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Species</label>
                                <InputText class="form-control" @bind-Value="pet.Species" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Breed</label>
                                <InputText class="form-control" @bind-Value="pet.Breed" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Weight (kg)</label>
                                <InputNumber class="form-control" @bind-Value="pet.Weight" />
                            </div>
                            <button type="submit" class="btn btn-primary">Save</button>
                        </EditForm>
                    }
                    else
                    {
                        <p><strong>Species:</strong> @pet.Species</p>
                        <p><strong>Breed:</strong> @pet.Breed</p>
                        <p><strong>DOB:</strong> @pet.DateOfBirth.ToShortDateString()</p>
                        <p><strong>Weight:</strong> @pet.Weight kg</p>
                        <p><strong>Owner:</strong> @pet.Owner.FirstName @pet.Owner.LastName</p>
                        <p><strong>Phone:</strong> @pet.Owner.Phone</p>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-8">
            <div class="d-flex justify-content-between align-items-center mb-3">
                <h3>Medical History</h3>
                <button class="btn btn-success" @onclick="ShowAddNote">+ Add Treatment Note</button>
            </div>

            @if (showNoteForm)
            {
                <div class="card mb-3 border-success">
                    <div class="card-body">
                        <EditForm Model="editingNote" OnValidSubmit="SaveNote" FormName="noteForm">
                            <div class="row">
                                <div class="col-md-6">
                                    <label class="form-label">Date</label>
                                    <InputDate class="form-control" @bind-Value="editingNote.Date" />
                                </div>
                                <div class="col-md-6">
                                    <label class="form-label">Veterinarian</label>
                                    <InputText class="form-control" @bind-Value="editingNote.VeterinarianName" />
                                </div>
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Diagnosis</label>
                                <InputText class="form-control" @bind-Value="editingNote.Diagnosis" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Treatment</label>
                                <InputTextArea class="form-control" @bind-Value="editingNote.Treatment" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Medications</label>
                                <InputText class="form-control" @bind-Value="editingNote.Medications" />
                            </div>
                            <div class="mb-2">
                                <label class="form-label">Notes</label>
                                <InputTextArea class="form-control" @bind-Value="editingNote.Notes" />
                            </div>
                            <button type="submit" class="btn btn-success">Save Note</button>
                            <button type="button" class="btn btn-secondary" @onclick="() => showNoteForm = false">Cancel</button>
                        </EditForm>
                    </div>
                </div>
            }

            @if (notes.Any())
            {
                @foreach (var note in notes)
                {
                    <div class="card mb-2">
                        <div class="card-header d-flex justify-content-between">
                            <span><strong>@note.Date.ToShortDateString()</strong> — @note.Diagnosis</span>
                            <span class="text-muted">Dr. @note.VeterinarianName</span>
                        </div>
                        <div class="card-body">
                            <p><strong>Treatment:</strong> @note.Treatment</p>
                            @if (!string.IsNullOrEmpty(note.Medications))
                            {
                                <p><strong>Medications:</strong> @note.Medications</p>
                            }
                            @if (!string.IsNullOrEmpty(note.Notes))
                            {
                                <p><strong>Notes:</strong> @note.Notes</p>
                            }
                        </div>
                    </div>
                }
            }
            else
            {
                <p class="text-muted">No medical history recorded yet.</p>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int PetId { get; set; }

    private Pet? pet;
    private List<TreatmentNote> notes = new();
    private bool editingPetInfo;
    private bool showNoteForm;
    private TreatmentNote editingNote = new();

    protected override async Task OnInitializedAsync()
    {
        await LoadData();
    }

    private async Task LoadData()
    {
        pet = await Db.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == PetId);
        notes = await Db.TreatmentNotes
            .Where(n => n.PetId == PetId)
            .OrderByDescending(n => n.Date)
            .ToListAsync();
    }

    private void ToggleEditPet() => editingPetInfo = !editingPetInfo;

    private async Task SavePetInfo()
    {
        await Db.SaveChangesAsync();
        editingPetInfo = false;
    }

    private void ShowAddNote()
    {
        editingNote = new TreatmentNote { PetId = PetId, Date = DateTime.Today };
        showNoteForm = true;
    }

    private async Task SaveNote()
    {
        Db.TreatmentNotes.Add(editingNote);
        await Db.SaveChangesAsync();
        showNoteForm = false;
        await LoadData();
    }
}

@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Appointments</PageTitle>

<h1>Appointment Scheduling</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">View Date</label>
        <input type="date" class="form-control" @bind="selectedDate" @bind:after="LoadAppointments" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-primary" @onclick="ShowNewAppointmentForm">+ New Appointment</button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-3 border-primary">
        <div class="card-header">@(editingAppointment.Id == 0 ? "Schedule New Appointment" : "Edit Appointment")</div>
        <div class="card-body">
            <EditForm Model="editingAppointment" OnValidSubmit="SaveAppointment" FormName="appointmentForm">
                <div class="row">
                    <div class="col-md-3">
                        <label class="form-label">Pet</label>
                        <InputSelect class="form-select" @bind-Value="editingAppointment.PetId">
                            <option value="0">Select pet...</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FirstName @pet.Owner.LastName)</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" @bind-Value="appointmentDate" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Start Time</label>
                        <InputSelect class="form-select" @bind-Value="startTimeSlot">
                            @foreach (var slot in timeSlots)
                            {
                                <option value="@slot">@slot</option>
                            }
                        </InputSelect>
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Duration (min)</label>
                        <InputSelect class="form-select" @bind-Value="durationMinutes">
                            <option value="15">15</option>
                            <option value="30">30</option>
                            <option value="45">45</option>
                            <option value="60">60</option>
                        </InputSelect>
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Veterinarian</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.VeterinarianName" />
                    </div>
                </div>
                <div class="row mt-2">
                    <div class="col-md-6">
                        <label class="form-label">Reason</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Reason" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Notes</label>
                        <InputText class="form-control" @bind-Value="editingAppointment.Notes" />
                    </div>
                </div>
                @if (!string.IsNullOrEmpty(formError))
                {
                    <div class="alert alert-danger mt-2">@formError</div>
                }
                <button type="submit" class="btn btn-primary mt-2">Save</button>
                <button type="button" class="btn btn-secondary mt-2" @onclick="CancelForm">Cancel</button>
            </EditForm>
        </div>
    </div>
}

<h4>Schedule for @selectedDate.ToString("D")</h4>

<div class="row">
    <div class="col-md-8">
        <table class="table table-bordered">
            <thead>
                <tr><th style="width:100px">Time</th><th>Appointment</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
                @foreach (var slot in timeSlots)
                {
                    var aptsInSlot = dayAppointments.Where(a => a.StartTime.ToString("HH:mm") == slot).ToList();
                    <tr class="@(aptsInSlot.Any() ? "table-info" : "")">
                        <td>@slot</td>
                        <td>
                            @if (aptsInSlot.Any())
                            {
                                @foreach (var apt in aptsInSlot)
                                {
                                    <span>@apt.Pet.Name — @apt.Reason (Dr. @apt.VeterinarianName)</span>
                                }
                            }
                            else
                            {
                                <span class="text-muted">Available</span>
                            }
                        </td>
                        <td>
                            @foreach (var apt in aptsInSlot)
                            {
                                <span class="badge @GetStatusBadge(apt.Status)">@apt.Status</span>
                            }
                        </td>
                        <td>
                            @foreach (var apt in aptsInSlot)
                            {
                                @if (apt.Status == AppointmentStatus.Scheduled)
                                {
                                    <button class="btn btn-sm btn-outline-warning" @onclick="() => Reschedule(apt)">Reschedule</button>
                                    <button class="btn btn-sm btn-outline-success" @onclick="() => Complete(apt)">Complete</button>
                                    <button class="btn btn-sm btn-outline-danger" @onclick="() => Cancel(apt)">Cancel</button>
                                }
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-header">Availability Summary</div>
            <div class="card-body">
                <p><strong>Total slots:</strong> @timeSlots.Count</p>
                <p><strong>Booked:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled)</p>
                <p><strong>Available:</strong> @(timeSlots.Count - dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled))</p>
                <p><strong>Completed:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Completed)</p>
                <p><strong>Cancelled:</strong> @dayAppointments.Count(a => a.Status == AppointmentStatus.Cancelled)</p>
            </div>
        </div>
    </div>
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private DateTime appointmentDate = DateTime.Today;
    private string startTimeSlot = "09:00";
    private int durationMinutes = 30;
    private List<Appointment> dayAppointments = new();
    private List<Pet> pets = new();
    private bool showForm;
    private Appointment editingAppointment = new();
    private string formError = "";

    private List<string> timeSlots = Enumerable.Range(8, 11)
        .SelectMany(h => new[] { $"{h:D2}:00", $"{h:D2}:30" })
        .ToList();

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        dayAppointments = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .Where(a => a.StartTime.Date == selectedDate.Date)
            .OrderBy(a => a.StartTime)
            .ToListAsync();
    }

    private void ShowNewAppointmentForm()
    {
        editingAppointment = new Appointment();
        appointmentDate = selectedDate;
        startTimeSlot = "09:00";
        durationMinutes = 30;
        formError = "";
        showForm = true;
    }

    private void CancelForm() => showForm = false;

    private async Task SaveAppointment()
    {
        formError = "";
        if (editingAppointment.PetId == 0)
        {
            formError = "Please select a pet.";
            return;
        }

        var timeParts = startTimeSlot.Split(':');
        var start = appointmentDate.Date.AddHours(int.Parse(timeParts[0])).AddMinutes(int.Parse(timeParts[1]));
        var end = start.AddMinutes(durationMinutes);

        var conflict = await Db.Appointments.AnyAsync(a =>
            a.Id != editingAppointment.Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.StartTime < end && a.EndTime > start);

        if (conflict)
        {
            formError = "This time slot conflicts with an existing appointment.";
            return;
        }

        editingAppointment.StartTime = start;
        editingAppointment.EndTime = end;
        editingAppointment.Status = AppointmentStatus.Scheduled;

        if (editingAppointment.Id == 0)
            Db.Appointments.Add(editingAppointment);
        else
            Db.Appointments.Update(editingAppointment);

        await Db.SaveChangesAsync();
        showForm = false;
        await LoadAppointments();
    }

    private void Reschedule(Appointment apt)
    {
        editingAppointment = apt;
        appointmentDate = apt.StartTime.Date;
        startTimeSlot = apt.StartTime.ToString("HH:mm");
        durationMinutes = (int)(apt.EndTime - apt.StartTime).TotalMinutes;
        formError = "";
        showForm = true;
    }

    private async Task Complete(Appointment apt)
    {
        apt.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private async Task Cancel(Appointment apt)
    {
        apt.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        await LoadAppointments();
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/billing"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Billing</PageTitle>

<h1>Billing & Payments</h1>

<ul class="nav nav-tabs mb-3">
    <li class="nav-item">
        <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
    </li>
    <li class="nav-item">
        <button class="nav-link @(activeTab == "payments" ? "active" : "")" @onclick='() => activeTab = "payments"'>Payment History</button>
    </li>
</ul>

@if (activeTab == "invoices")
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowNewInvoice">+ New Invoice</button>
    </div>

    @if (showInvoiceForm)
    {
        <div class="card mb-3 border-primary">
            <div class="card-header">Create Invoice</div>
            <div class="card-body">
                <div class="row mb-2">
                    <div class="col-md-4">
                        <label class="form-label">Pet</label>
                        <select class="form-select" @bind="newInvoicePetId">
                            <option value="0">Select pet...</option>
                            @foreach (var pet in pets)
                            {
                                <option value="@pet.Id">@pet.Name (@pet.Owner.FirstName @pet.Owner.LastName)</option>
                            }
                        </select>
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Due Date</label>
                        <input type="date" class="form-control" @bind="newInvoiceDueDate" />
                    </div>
                </div>

                <h6>Line Items</h6>
                @for (int i = 0; i < lineItems.Count; i++)
                {
                    var idx = i;
                    <div class="row mb-1">
                        <div class="col-md-8">
                            <input type="text" class="form-control" placeholder="Description" @bind="lineItems[idx].Description" />
                        </div>
                        <div class="col-md-3">
